mapper.select:
select d.id, d.title, u.real_name as sender, u.avatar, CASE WHEN r.code = 3 THEN 'admin' WHEN r.code = 2 THEN 'teacher' ELSE 'student' END as role, COALESCE(d.comment_count, 0) as commentCount, COALESCE(d.like_count, 0) as likeCount, COALESCE(d.view_count, 0) as viewCount, d.visibility, d.content, CASE WHEN EXISTS (SELECT 1 FROM t_like WHERE discussion_id = d.id AND user_id = #{userId} AND reply_id IS NULL) THEN true ELSE false END as liked, d.create_time from t_discussion as d join t_user as u on d.user_id = u.id left join t_role as r on u.role_id = r.id
d.user_id = #{userId}
and d.title like concat('%',#{title},'%')
and d.grade_id = #{gradeId}
order by d.create_time desc
